// ============================================================
// PREPARE transaction/order data
// ============================================================
const input = $input.first().json;
const tenant = input.tenant;

if (!tenant || !tenant.business_id) throw new Error('Missing tenant.business_id');
if (!input.customer) throw new Error('Missing customer data');

const now = new Date();
const dateStr = now.toISOString().slice(0,10).replace(/-/g,'');
const timeStr = now.toISOString().slice(11,16).replace(':','');
const orderNumber = input.order_number || `ORD-${dateStr}-${timeStr}-${Math.floor(Math.random() * 900) + 100}`;

// Calculate total if not provided
let totalEgp = parseFloat(input.total_egp || 0);
if (!totalEgp && Array.isArray(input.items)) {
  totalEgp = input.items.reduce((sum, item) => sum + (parseFloat(item.price || 0) * parseInt(item.qty || 1)), 0);
}

return {
  json: {
    business_id:      tenant.business_id,
    order_id:         tenant.order_id || '',
    order_number:     orderNumber,
    conversation_id:  input.conversation_id || null,
    customer_id:      input.customer.id || input.customer.phone || 'UNKNOWN',
    customer_name:    input.customer.name || '',
    customer_phone:   input.customer.phone || input.customer.id || '',
    order_type:       input.order_type || 'general',
    items:            JSON.stringify(input.items || []),
    total_egp:        totalEgp,
    delivery_address: input.delivery_address || '',
    payment_method:   input.payment_method || '',
    notes:            input.notes || '',
    status:           input.status || 'pending',
    created_at:       now.toISOString()
  }
};

const insertedOrder = $('INSERT_ORDER').first().json;
const orderArr = Array.isArray(insertedOrder) ? insertedOrder : [insertedOrder];
const order = orderArr[0] || {};

return {
  json: {
    success: true,
    order_id:     order.id || null,
    order_number: $('TRANSACTION_PREPARE').first().json.order_number,
    total_egp:    $('TRANSACTION_PREPARE').first().json.total_egp,
    status:       $('TRANSACTION_PREPARE').first().json.status,
    message:      `تم حفظ الطلب رقم ${$('TRANSACTION_PREPARE').first().json.order_number} بنجاح ✅`
  }
};
